'use strict';

function buildRequest(url, token) {
  return {
    url: new URL(url).toString(),
    headers: {
      accept: 'application/json',
      authorization: `Bearer ${token}`,
    },
    sensitiveHeaders: [],
  };
}

module.exports = { buildRequest };

repo_files.src/redirect_policy.js:
'use strict';

function followRedirect(request, location) {
  const source = new URL(request.url);
  const target = new URL(location, source);
  const headers = { ...request.headers };

  if (target.hostname !== source.hostname) {
    for (const name of request.sensitiveHeaders || []) {
      delete headers[name.toLowerCase()];
    }
  }

  return { ...request, url: target.toString(), headers };
}

module.exports = { followRedirect };

repo_files.src/redirect_status.js:
'use strict';

function statusAllowsRedirect(status) {
  return [301, 302, 303, 307, 308].includes(status);
}

module.exports = { statusAllowsRedirect };

