'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { buildRequest } = require('../src/request_options');
const { followRedirect } = require('../src/redirect_policy');
const { statusAllowsRedirect } = require('../src/redirect_status');

test('same-origin redirects retain bearer authorization', () => {
  const request = buildRequest('https://api.example.test/v1/jobs', 'token-7');
  const redirected = followRedirect(request, '/v2/jobs');
  assert.equal(redirected.url, 'https://api.example.test/v2/jobs');
  assert.equal(redirected.headers.authorization, 'Bearer token-7');
});

test('redirect status classification is stable', () => {
  assert.equal(statusAllowsRedirect(307), true);
  assert.equal(statusAllowsRedirect(200), false);
});
